function makeGreeter(greeting) {
  // 'greeting' lives in makeGreeter's scope
  return function(name) {
    // This inner function closes over 'greeting'
    return `${greeting}, ${name}!`;
  };
}

const hello = makeGreeter('Hello');
const hi    = makeGreeter('Hi');

hello('Alice'); // 'Hello, Alice!'
hi('Bob');      // 'Hi, Bob!'

// makeGreeter has returned, but 'greeting' is still alive
// because hello and hi each hold a reference to their own copy

function makeCounter(initialValue = 0) {
  let count = initialValue; // private — inaccessible from outside

  return {
    increment() { count++;  },
    decrement() { count--;  },
    reset()     { count = initialValue; },
    value()     { return count; },
  };
}

const c = makeCounter(10);
c.increment();
c.increment();
console.log(c.value()); // 12
// console.log(c.count); // undefined — truly private via closure
// c.count = 100;        // no effect — count is not a property

// Bug — var creates ONE i shared by all callbacks
for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 0);
}
// prints: 3, 3, 3 — by the time callbacks run, i is 3

// Fix 1: use let (per-iteration binding — ES2015+)
for (let i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 0);
}
// prints: 0, 1, 2

// Fix 2: IIFE (pre-ES2015 pattern, seen in legacy code)
for (var i = 0; i < 3; i++) {
  (function(j) {
    setTimeout(() => console.log(j), 0);
  })(i); // captures current i as j
}
// prints: 0, 1, 2

// Real-world scenario — attaching event handlers in a loop
const buttons = document.querySelectorAll('button');
for (let i = 0; i < buttons.length; i++) {
  buttons[i].addEventListener('click', () => console.log(i)); // correct with let
}

const userModule = (() => {
  // Private state
  let currentUser = null;
  const sessionKey = 'user-session';

  // Private helper
  function validateUser(user) {
    return user && user.id && user.name;
  }

  // Public API
  return {
    login(user) {
      if (!validateUser(user)) throw new Error('Invalid user');
      currentUser = user;
      sessionStorage.setItem(sessionKey, JSON.stringify(user));
    },
    logout() {
      currentUser = null;
      sessionStorage.removeItem(sessionKey);
    },
    getCurrentUser() {
      if (!currentUser) {
        const stored = sessionStorage.getItem(sessionKey);
        if (stored) currentUser = JSON.parse(stored);
      }
      return currentUser;
    },
  };
})(); // IIFE — immediately creates and returns the module

userModule.login({ id: 1, name: 'Alice' });
userModule.getCurrentUser(); // { id: 1, name: 'Alice' }
// userModule.currentUser — undefined (private)

function memoize(fn) {
  const cache = new Map(); // private cache via closure

  return function(...args) {
    const key = JSON.stringify(args);
    if (cache.has(key)) {
      return cache.get(key); // return cached result
    }
    const result = fn.apply(this, args);
    cache.set(key, result);
    return result;
  };
}

// Expensive computation
const fibonacci = memoize(function fib(n) {
  if (n <= 1) return n;
  return fibonacci(n - 1) + fibonacci(n - 2); // recursive calls also memoized
});

fibonacci(40); // computed once
fibonacci(40); // instant — from cache

// Angular: memoize expensive template transforms
@Pipe({ name: 'expensiveFormat', pure: true })
export class ExpensiveFormatPipe implements PipeTransform {
  // Angular pure pipes are effectively memoized by reference equality
  transform(value: string): string {
    return heavyProcess(value);
  }
}

// LEAK — the arrow function closes over 'this' (the component)
// The interval runs forever, preventing garbage collection
@Component({ ... })
export class DashboardComponent {
  ngOnInit() {
    setInterval(() => {
      this.updateStats(); // 'this' is captured
    }, 5000);
    // No clearInterval — component is never collected
  }
}

// FIX — store the id and clear in ngOnDestroy
@Component({ ... })
export class DashboardComponent implements OnDestroy {
  private intervalId: ReturnType<typeof setInterval> | null = null;

  ngOnInit() {
    this.intervalId = setInterval(() => this.updateStats(), 5000);
  }

  ngOnDestroy() {
    if (this.intervalId !== null) {
      clearInterval(this.intervalId);
      this.intervalId = null;
    }
  }
}

// LEAK — subscription lives forever after component destroy
ngOnInit() {
  this.service.data$.subscribe(data => {
    this.data = data; // closure keeps component alive
  });
}

// FIX — unsubscribe in ngOnDestroy (or use takeUntilDestroyed)
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

@Component({ ... })
export class DataComponent {
  data: Data[] = [];
  private destroyRef = inject(DestroyRef);

  ngOnInit() {
    this.service.data$.pipe(
      takeUntilDestroyed(this.destroyRef),
    ).subscribe(data => {
      this.data = data;
    });
  }
}

// Alternative: async pipe (auto-unsubscribes)
// template: {{ data$ | async }}

// Each call to the factory creates a new closure scope
export const THEME_TOKEN = new InjectionToken<Theme>('theme', {
  providedIn: 'root',
  factory: () => {
    const storage = inject(LocalStorageService);
    // factory is a closure — captures storage via inject()
    return storage.get<Theme>('theme') ?? defaultTheme;
  },
});

@Component({ ... })
export class ProductComponent {
  product = input.required<Product>();
  quantity = signal(1);

  // computed() creates a closure over product and quantity signals
  subtotal = computed(() => this.product().price * this.quantity());
  tax      = computed(() => this.subtotal() * 0.08);
  total    = computed(() => this.subtotal() + this.tax());
}

@Component({ ... })
export class SearchComponent {
  readonly query = signal('');
  readonly minLength = 3;  // closed over in the pipe

  readonly results$ = toObservable(this.query).pipe(
    filter(q => q.length >= this.minLength), // arrow fn closes over this
    debounceTime(300),
    switchMap(q => this.searchService.search(q)),
  );
}

// A spy factory returns a fresh closure each time — independent call log
function createSpy<T extends (...args: any[]) => any>(impl?: T) {
  const calls: Parameters<T>[] = [];
  const spy = (...args: Parameters<T>) => {
    calls.push(args);
    return impl?.(...args);
  };
  spy.calls = calls;
  spy.callCount = () => calls.length;
  spy.reset = () => calls.splice(0);
  return spy;
}

const saveSpy = createSpy((id: number) => Promise.resolve({ id }));
// Each createSpy() call gets an independent `calls` array via closure

describe('CartService', () => {
  let items: string[];             // declared in describe scope
  let addItem: (item: string) => void;

  beforeEach(() => {
    // Re-create closure on each test — isolation guaranteed
    items = [];
    addItem = (item: string) => { items.push(item); };
  });

  it('adds one item', () => {
    addItem('apple');
    expect(items).toEqual(['apple']);
  });

  it('starts empty', () => {
    // items is a fresh [] — prior test mutations do not bleed
    expect(items).toHaveLength(0);
  });
});

@Component({ ... })
export class ProductListComponent {
  products = signal<Product[]>([]);

  // Bad: new function object created every render
  // getFilter() { return (p: Product) => p.active; }

  // Good: closure computed once, updated only when products change
  activeProducts = computed(() =>
    this.products().filter(p => p.active)
  );
}
